@app.route('/authorize_consent', methods=['POST'])
def authorize_consent():
    if not session.get('auth_request'):
        return jsonify({"error": "no pending authorization request"}), 400

    user_id = request.form.get('username') # Simulate user authentication
    if not user_id:
        return jsonify({"error": "username required for simulation"}), 400

    auth_request = session.pop('auth_request')
    client_id = auth_request['client_id']
    redirect_uri = auth_request['redirect_uri']
    state = auth_request['state']

    # Generate an authorization code
    code = os.urandom(16).hex()
    auth_codes[code] = user_id  # Store code with the user ID

    # Redirect back to the client with the authorization code
    response_url = f"{redirect_uri}?code={code}"
    if state:
        response_url += f"&state={state}"
    return redirect(response_url)

# --- Token Endpoint ---
@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    # Basic validation
    if not all([grant_type, code, redirect_uri, client_id, client_secret]):
        return jsonify({"error": "missing parameters"}), 400

    if grant_type != 'authorization_code':
        return jsonify({"error": "unsupported grant_type"}), 400

    if client_id not in clients or clients[client_id]["client_secret"] != client_secret:
        return jsonify({"error": "invalid client_credentials"}), 401

    if clients[client_id]["redirect_uri"] != redirect_uri:
        return jsonify({"error": "invalid redirect_uri"}), 400

    if code not in auth_codes:
        return jsonify({"error": "invalid or expired authorization code"}), 400

    # Retrieve user_id associated with the code
    user_id = auth_codes[code]
    # For retry resilience, we keep the code in auth_codes.
    # In a production system with expiration, you might delete it here
    # or mark it as used to prevent re-use after a certain period/number of uses.

    # Generate an access token (and optionally refresh token)
    # For this example, access token is just a random string
